// api/userRouter.ts
async function assertUserInScope(ctx, targetId) {
  if (isSuperAdmin(ctx.user)) return;
  const target = await findUserById(targetId);
  if (!target || target.companyId !== ctx.user.companyId) {
    throw new TRPCError({ code: "FORBIDDEN", message: "You do not have access to this user." });
  }
}
var userRouter = createRouter({
  list: adminQuery.query(async ({ ctx }) => {
    if (isSuperAdmin(ctx.user)) return findAllUsers();
    if (!ctx.user.companyId) return [];
    return findUsersByCompany(ctx.user.companyId);
  }),
  listCallers: adminQuery.query(async ({ ctx }) => {
    return findCallersByAdmin(ctx.user.id);
  }),
  getById: adminQuery.input(external_exports.object({ id: external_exports.number() })).query(async ({ ctx, input }) => {
    await assertUserInScope(ctx, input.id);
    return findUserById(input.id);
  }),
  create: adminQuery.input(external_exports.object({
    name: external_exports.string().min(1),
    email: external_exports.string().email(),
    phone: external_exports.string().optional(),
    role: external_exports.enum(["admin", "caller", "viewer"]),
    unionId: external_exports.string().optional(),
    companyId: external_exports.number().optional(),
    extension: external_exports.string().optional(),
    dailyCallLimit: external_exports.number().default(200).optional(),
    permissions: external_exports.array(external_exports.string()).optional(),
    password: external_exports.string().optional()
  })).mutation(async ({ ctx, input }) => {
    const { password, ...rest } = input;
    const finalUnionId = input.unionId || `user-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const companyId = isSuperAdmin(ctx.user) ? input.companyId || ctx.user.companyId || 1 : ctx.user.companyId || 1;
    const id = await createUser({
      ...rest,
      unionId: finalUnionId,
      companyId,
      createdBy: ctx.user.id,
      role: input.role,
      status: "active",
      password: password || void 0,
      sipCredentials: password ? { username: input.email, password, domain: "local" } : void 0
    });
    return { id, success: true };
  }),
  update: adminQuery.input(external_exports.object({
    id: external_exports.number(),
    data: external_exports.object({
      name: external_exports.string().min(1).optional(),
      email: external_exports.string().email().optional(),
      phone: external_exports.string().optional(),
      role: external_exports.enum(["admin", "caller", "viewer", "superadmin"]).optional(),
      status: external_exports.enum(["active", "inactive", "suspended"]).optional(),
      extension: external_exports.string().optional(),
      dailyCallLimit: external_exports.number().optional(),
      permissions: external_exports.array(external_exports.string()).optional(),
      password: external_exports.string().optional()
    }).partial()
  })).mutation(async ({ ctx, input }) => {
    await assertUserInScope(ctx, input.id);
    if (input.data.role === "superadmin" && !isSuperAdmin(ctx.user)) {
      throw new TRPCError({ code: "FORBIDDEN", message: "Only a superadmin can grant the superadmin role." });
    }
    const updateData = { ...input.data };
    if (updateData.password) {
      updateData.sipCredentials = {
        username: updateData.email || "",
        password: updateData.password,
        domain: "local"
      };
    }
    await updateUser(input.id, updateData);
    return { success: true };
  }),
  delete: adminQuery.input(external_exports.object({ id: external_exports.number() })).mutation(async ({ ctx, input }) => {
    await assertUserInScope(ctx, input.id);
    await deleteUser(input.id);
    return { success: true };
  }),
  me: authedQuery.query(async ({ ctx }) => {
    return ctx.user;
  }),
  updateMe: authedQuery.input(external_exports.object({
    name: external_exports.string().optional(),
    phone: external_exports.string().optional(),
    email: external_exports.string().email().optional()
  })).mutation(async ({ ctx, input }) => {
    await updateUser(ctx.user.id, input);
    return { success: true };
  }),
  // For callers to see their own profile
  myProfile: callerQuery.query(async ({ ctx }) => {
    return findUserById(ctx.user.id);
  })
});

