async function getCallStats(callerId, dateFrom, dateTo) {
  try {
    const db = getDb();
    const conditions = [eq(calls.callerId, callerId)];
    if (dateFrom) conditions.push(gte(calls.createdAt, dateFrom));
    if (dateTo) conditions.push(lte(calls.createdAt, dateTo));
    const [totalResult] = await db.select({ value: count() }).from(calls).where(and(...conditions));
    const [connectedResult] = await db.select({ value: count() }).from(calls).where(and(...conditions, eq(calls.status, "connected")));
    const [failedResult] = await db.select({ value: count() }).from(calls).where(and(...conditions, eq(calls.status, "failed")));
    const avgDurationResult = await db.select({
      avg: sql`AVG(${calls.duration})`
    }).from(calls).where(and(...conditions, eq(calls.status, "connected")));
    return {
      total: totalResult.value,
      connected: connectedResult.value,
      failed: failedResult.value,
      avgDuration: Math.round(avgDurationResult[0]?.avg || 0)
    };
  } catch {
    console.warn("[getCallStats] DB offline, falling back to local JSON store.");
    const data = readJsonDb5();
    const callerCalls = data.calls.filter((c) => c.callerId == callerId);
    const filtered = callerCalls.filter((c) => {
      const created = new Date(c.createdAt).getTime();
      if (dateFrom && created < dateFrom.getTime()) return false;
      if (dateTo && created > dateTo.getTime()) return false;
      return true;
    });
    const total = filtered.length;
    const connected = filtered.filter((c) => c.status === "connected" || c.status === "completed").length;
    const failed = filtered.filter((c) => c.status === "failed").length;
    const durations = filtered.filter((c) => (c.status === "connected" || c.status === "completed") && c.duration > 0).map((c) => c.duration);
    const avgDuration = durations.length > 0 ? Math.round(durations.reduce((a, b) => a + b, 0) / durations.length) : 0;
    return {
      total,
      connected,
      failed,
      avgDuration
    };
  }
}
