var monitoringRouter = createRouter({
  // ─── Start Monitoring a Caller's Call ───
  startListening: adminQuery.input(external_exports.object({
    callerId: external_exports.number(),
    callId: external_exports.number()
  })).mutation(async ({ ctx, input }) => {
    const monitorChannel = `monitor_${ctx.user.id}_${input.callerId}_${Date.now()}`;
    const id = await createMonitorSession({
      adminId: ctx.user.id,
      callerId: input.callerId,
      callId: input.callId,
      monitorChannel,
      status: "listening"
    });
    return { id, monitorChannel, success: true };
  }),
  // ─── Stop Monitoring ───
  stopListening: adminQuery.input(external_exports.object({ sessionId: external_exports.number() })).mutation(async ({ input }) => {
    await endMonitorSession(input.sessionId);
    return { success: true };
  }),
  // ─── Get Active Monitoring Sessions ───
  mySessions: adminQuery.query(async ({ ctx }) => {
    return findActiveMonitorSessions(ctx.user.id);
  }),
  // ─── Get Active Calls for Monitoring ───
  activeCalls: adminQuery.input(external_exports.object({ companyId: external_exports.number().optional() })).query(async ({ ctx, input }) => {
    const companyId = requireCompanyScope(ctx.user, input.companyId);
    return getActiveCallsForMonitoring(companyId);
  }),
  // ─── Caller Day Report (date-wise full-day performance) ───
  callerDayReport: adminQuery.input(external_exports.object({
    callerId: external_exports.number(),
    date: external_exports.string()
    // YYYY-MM-DD
  })).query(async ({ input }) => {
    return getCallerDayReport(input.callerId, input.date);
  }),
  // ─── Get Caller's Active Call ───
  callerActiveCall: adminQuery.input(external_exports.object({ callerId: external_exports.number() })).query(async ({ input }) => {
    return getCallerActiveCall(input.callerId);
  }),
  // ─── Barge In (Force Join Call) ───
  bargeIn: adminQuery.input(external_exports.object({
    callerId: external_exports.number(),
    callId: external_exports.number()
  })).mutation(async ({ ctx, input }) => {
    const monitorChannel = `barge_${ctx.user.id}_${input.callerId}_${Date.now()}`;
    const id = await createMonitorSession({
      adminId: ctx.user.id,
      callerId: input.callerId,
      callId: input.callId,
      monitorChannel,
      status: "listening"
    });
    return { id, monitorChannel, success: true, mode: "barge" };
  }),
  // ─── Whisper (Private Message to Caller) ───
  whisper: adminQuery.input(external_exports.object({
    callerId: external_exports.number(),
    callId: external_exports.number(),
    message: external_exports.string()
  })).mutation(async ({ input }) => {
    return { success: true, message: input.message, mode: "whisper" };
  })
});

